public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats (Public)")]
    public int maxHealth = 100;
    public int currentHealth = 100;

    public int currencySoft = 0;
    public int currencyPremium = 0;

    [Header("Combat (Public)")]
    public int level = 1;
    public float baseDamage = 10f;
    public float damageMultiplier = 1f;
    public float critChance = 0.1f;
    public float critMultiplier = 2f;

    [Header("Defense (Public)")]
    public float armor = 0f;
    public float damageReductionPercent = 0f;

    [Header("Progression / Discounts (Public)")]
    public float shopDiscountPercent = 0f;

    public event Action<int, int> OnHealthChanged;
    public event Action<int, int> OnCurrencyChanged;
    public event Action OnDied;

    void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;
        int old = currentHealth;
        currentHealth = Mathf.Clamp(currentHealth + amount, 0, maxHealth);
        if (currentHealth != old) OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public void SetMaxHealth(int newMax)
    {
        maxHealth = Mathf.Max(1, newMax);
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public float CalculateOutgoingDamage(System.Random rng = null)
    {
        float dmg = baseDamage * damageMultiplier;
        dmg *= 1f + Mathf.Clamp01((level - 1) * 0.02f);

        float roll = rng != null ? (float)rng.NextDouble() : UnityEngine.Random.value;
        bool isCrit = roll < Mathf.Clamp01(critChance);
        if (isCrit) dmg *= Mathf.Max(1f, critMultiplier);

        return Mathf.Max(0f, dmg);
    }

    public int ApplyIncomingDamage(float rawDamage)
    {
        if (rawDamage <= 0f || currentHealth <= 0) return 0;

        float afterArmor = Mathf.Max(0f, rawDamage - Mathf.Max(0f, armor));
        float dr = Mathf.Clamp01(damageReductionPercent);
        float finalDamage = afterArmor * (1f - dr);

        int dmgInt = Mathf.Max(1, Mathf.RoundToInt(finalDamage));
        int old = currentHealth;
        currentHealth = Mathf.Clamp(currentHealth - dmgInt, 0, maxHealth);

        if (currentHealth != old) OnHealthChanged?.Invoke(currentHealth, maxHealth);
        if (currentHealth == 0) OnDied?.Invoke();

        return dmgInt;
    }

    public void AddSoftCurrency(int amount)
    {
        if (amount == 0) return;
        currencySoft = Mathf.Max(0, currencySoft + amount);
        OnCurrencyChanged?.Invoke(currencySoft, currencyPremium);
    }

    public void AddPremiumCurrency(int amount)
    {
        if (amount == 0) return;
        currencyPremium = Mathf.Max(0, currencyPremium + amount);
        OnCurrencyChanged?.Invoke(currencySoft, currencyPremium);
    }

    public bool TrySpendSoft(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (currencySoft < amount) return false;
        currencySoft -= amount;
        OnCurrencyChanged?.Invoke(currencySoft, currencyPremium);
        return true;
    }

    public bool TrySpendPremium(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (currencyPremium < amount) return false;
        currencyPremium -= amount;
        OnCurrencyChanged?.Invoke(currencySoft, currencyPremium);
        return true;
    }
}

public enum CurrencyType
{
    Soft,
    Premium
}

public enum ShopEffectType
{
    AddSoftCurrency,
    AddPremiumCurrency,
    Heal,
    IncreaseMaxHealth,
    IncreaseBaseDamage,
    IncreaseDamageMultiplier,
    IncreaseArmor,
    IncreaseDamageReductionPercent,
    IncreaseCritChance,
