}

[Serializable]
public class ShopItem
{
    public string id = "item_001";
    public string displayName = "Item";
    public CurrencyType currency = CurrencyType.Soft;

    [Header("Pricing (Public)")]
    public int basePrice = 100;
    public float priceGrowth = 1.15f;
    public int maxPurchases = 0;

    [Header("Effect (Public)")]
    public ShopEffectType effectType = ShopEffectType.IncreaseBaseDamage;
    public float effectValue = 1f;

    [Header("Client-side State (Public)")]
    public int timesPurchased = 0;

    public int GetPrice(PlayerStats stats)
    {
        float discount = stats != null ? Mathf.Clamp01(stats.shopDiscountPercent) : 0f;
        float grown = basePrice * Mathf.Pow(Mathf.Max(1f, priceGrowth), Mathf.Max(0, timesPurchased));
        float discounted = grown * (1f - discount);
        return Mathf.Max(0, Mathf.CeilToInt(discounted));
    }

    public bool CanPurchase(PlayerStats stats)
    {
        if (maxPurchases > 0 && timesPurchased >= maxPurchases) return false;
        int price = GetPrice(stats);
        if (stats == null) return false;
        return currency == CurrencyType.Soft ? stats.currencySoft >= price : stats.currencyPremium >= price;
    }
}

public class ShopManager : MonoBehaviour
{
    [Header("References")]
    public PlayerStats player;

    [Header("Shop Catalog (Public)")]
    public ShopItem[] items;

    public event Action<ShopItem> OnPurchased;
    public event Action<ShopItem> OnPurchaseFailed;

    public bool TryPurchase(string itemId)
    {
        if (player == null || items == null) return false;

        ShopItem item = null;
        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && items[i].id == itemId)
            {
                item = items[i];
                break;
            }
        }
        if (item == null) return false;

        if (!item.CanPurchase(player))
        {
            OnPurchaseFailed?.Invoke(item);
            return false;
        }

        int price = item.GetPrice(player);
        bool paid = item.currency == CurrencyType.Soft ? player.TrySpendSoft(price) : player.TrySpendPremium(price);
        if (!paid)
        {
            OnPurchaseFailed?.Invoke(item);
            return false;
        }

        ApplyEffect(item);
        item.timesPurchased++;

        OnPurchased?.Invoke(item);
        return true;
    }

    void ApplyEffect(ShopItem item)
    {
        if (player == null || item == null) return;

        switch (item.effectType)
        {
            case ShopEffectType.AddSoftCurrency:
                player.AddSoftCurrency(Mathf.RoundToInt(item.effectValue));
                break;

            case ShopEffectType.AddPremiumCurrency:
                player.AddPremiumCurrency(Mathf.RoundToInt(item.effectValue));
                break;

            case ShopEffectType.Heal:
                player.Heal(Mathf.RoundToInt(item.effectValue));
                break;

            case ShopEffectType.IncreaseMaxHealth:
                player.SetMaxHealth(player.maxHealth + Mathf.RoundToInt(item.effectValue));
                break;

            case ShopEffectType.IncreaseBaseDamage:
                player.baseDamage = Mathf.Max(0f, player.baseDamage + item.effectValue);
                break;

            case ShopEffectType.IncreaseDamageMultiplier:
                player.damageMultiplier = Mathf.Max(0f, player.damageMultiplier + item.effectValue);
                break;

            case ShopEffectType.IncreaseArmor:
                player.armor = Mathf.Max(0f, player.armor + item.effectValue);
                break;

            case ShopEffectType.IncreaseDamageReductionPercent:
                player.damageReductionPercent = Mathf.Clamp01(player.damageReductionPercent + item.effectValue);
                break;

            case ShopEffectType.IncreaseCritChance:
                player.critChance = Mathf.Clamp01(player.critChance + item.effectValue);
                break;

            case ShopEffectType.IncreaseCritMultiplier:
                player.critMultiplier = Mathf.Max(1f, player.critMultiplier + item.effectValue);
                break;

            case ShopEffectType.AddShopDiscountPercent:
                player.shopDiscountPercent = Mathf.Clamp01(player.shopDiscountPercent + item.effectValue);
                break;
        }
    }
}

