public class CombatController : MonoBehaviour
{
    [Header("References")]
    public PlayerStats player;
    public Enemy targetEnemy;

    [Header("Attack Settings (Public)")]
    public float attackCooldown = 0.5f;
    public bool autoAttack = true;

    float _nextAttackTime;

    void Update()
    {
        if (!autoAttack) return;
        if (player == null || targetEnemy == null) return;
        if (Time.time < _nextAttackTime) return;

        _nextAttackTime = Time.time + Mathf.Max(0.05f, attackCooldown);
        Attack();
    }

    public void Attack()
    {
        if (player == null || targetEnemy == null) return;
        float dmg = player.CalculateOutgoingDamage();
        targetEnemy.ApplyDamage(dmg);
    }
}

public class SimpleSaveManager : MonoBehaviour
{
