    public string keyCurrentHealth = "ps_currentHealth";
    public string keySoft = "ps_soft";
    public string keyPremium = "ps_premium";
    public string keyLevel = "ps_level";
    public string keyBaseDamage = "ps_baseDamage";
    public string keyDamageMultiplier = "ps_dmgMul";
    public string keyCritChance = "ps_crit";
    public string keyCritMultiplier = "ps_critMul";
    public string keyArmor = "ps_armor";
    public string keyDR = "ps_dr";
    public string keyDiscount = "ps_discount";

    public void Save()
    {
        if (player == null) return;

        PlayerPrefs.SetInt(keyMaxHealth, player.maxHealth);
        PlayerPrefs.SetInt(keyCurrentHealth, player.currentHealth);
        PlayerPrefs.SetInt(keySoft, player.currencySoft);
        PlayerPrefs.SetInt(keyPremium, player.currencyPremium);
        PlayerPrefs.SetInt(keyLevel, player.level);

        PlayerPrefs.SetFloat(keyBaseDamage, player.baseDamage);
        PlayerPrefs.SetFloat(keyDamageMultiplier, player.damageMultiplier);
        PlayerPrefs.SetFloat(keyCritChance, player.critChance);
        PlayerPrefs.SetFloat(keyCritMultiplier, player.critMultiplier);
        PlayerPrefs.SetFloat(keyArmor, player.armor);
        PlayerPrefs.SetFloat(keyDR, player.damageReductionPercent);
        PlayerPrefs.SetFloat(keyDiscount, player.shopDiscountPercent);

        PlayerPrefs.Save();
    }

    public void Load()
    {
        if (player == null) return;

        if (PlayerPrefs.HasKey(keyMaxHealth)) player.maxHealth = PlayerPrefs.GetInt(keyMaxHealth, player.maxHealth);
        if (PlayerPrefs.HasKey(keyCurrentHealth)) player.currentHealth = PlayerPrefs.GetInt(keyCurrentHealth, player.currentHealth);
        if (PlayerPrefs.HasKey(keySoft)) player.currencySoft = PlayerPrefs.GetInt(keySoft, player.currencySoft);
        if (PlayerPrefs.HasKey(keyPremium)) player.currencyPremium = PlayerPrefs.GetInt(keyPremium, player.currencyPremium);
        if (PlayerPrefs.HasKey(keyLevel)) player.level = PlayerPrefs.GetInt(keyLevel, player.level);

        if (PlayerPrefs.HasKey(keyBaseDamage)) player.baseDamage = PlayerPrefs.GetFloat(keyBaseDamage, player.baseDamage);
        if (PlayerPrefs.HasKey(keyDamageMultiplier)) player.damageMultiplier = PlayerPrefs.GetFloat(keyDamageMultiplier, player.damageMultiplier);
        if (PlayerPrefs.HasKey(keyCritChance)) player.critChance = PlayerPrefs.GetFloat(keyCritChance, player.critChance);
        if (PlayerPrefs.HasKey(keyCritMultiplier)) player.critMultiplier = PlayerPrefs.GetFloat(keyCritMultiplier, player.critMultiplier);
        if (PlayerPrefs.HasKey(keyArmor)) player.armor = PlayerPrefs.GetFloat(keyArmor, player.armor);
        if (PlayerPrefs.HasKey(keyDR)) player.damageReductionPercent = PlayerPrefs.GetFloat(keyDR, player.damageReductionPercent);
        if (PlayerPrefs.HasKey(keyDiscount)) player.shopDiscountPercent = PlayerPrefs.GetFloat(keyDiscount, player.shopDiscountPercent);

        player.maxHealth = Mathf.Max(1, player.maxHealth);
        player.currentHealth = Mathf.Clamp(player.currentHealth, 0, player.maxHealth);
        player.critChance = Mathf.Clamp01(player.critChance);
        player.damageReductionPercent = Mathf.Clamp01(player.damageReductionPercent);
        player.shopDiscountPercent = Mathf.Clamp01(player.shopDiscountPercent);
    }

    void OnApplicationPause(bool pause)
    {
        if (pause) Save();
    }

    void OnApplicationQuit()
    {
        Save();
    }
}

public class IAPManager : MonoBehaviour, IStoreListener
{
    [Header("References")]
    public PlayerStats player;

    [Header("Unity IAP Product IDs (Public)")]
    public string productPremiumSmall = "premium_small";
    public string productPremiumMedium = "premium_medium";
    public string productPremiumLarge = "premium_large";

    [Header("Rewards (Public)")]
    public int premiumSmallAmount = 100;
    public int premiumMediumAmount = 550;
    public int premiumLargeAmount = 1200;

    IStoreController _controller;
    IExtensionProvider _extensions;

    public bool IsInitialized => _controller != null && _extensions != null;

    void Start()
    {
        InitializeIAP();
    }

    public void InitializeIAP()
    {
        if (IsInitialized) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        builder.AddProduct(productPremiumSmall, ProductType.Consumable);
        builder.AddProduct(productPremiumMedium, ProductType.Consumable);
        builder.AddProduct(productPremiumLarge, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public void BuyPremiumSmall() { Buy(productPremiumSmall); }
    public void BuyPremiumMedium() { Buy(productPremiumMedium); }
    public void BuyPremiumLarge() { Buy(productPremiumLarge); }

    public void Buy(string productId)
    {
        if (!IsInitialized) return;
        Product product = _controller.products.WithID(productId);
        if (product == null || !product.availableToPurchase) return;
        _controller.InitiatePurchase(product);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        _controller = controller;
        _extensions = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error) { }
#if UNITY_2020_3_OR_NEWER
    public void OnInitializeFailed(InitializationFailureReason error, string message) { }
#endif

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs e)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        string id = e.purchasedProduct.definition.id;
        if (string.Equals(id, productPremiumSmall, StringComparison.Ordinal))
        {
            player.AddPremiumCurrency(premiumSmallAmount);
        }
        else if (string.Equals(id, productPremiumMedium, StringComparison.Ordinal))
        {
            player.AddPremiumCurrency(premiumMediumAmount);
        }
        else if (string.Equals(id, productPremiumLarge, StringComparison.Ordinal))
        {
            player.AddPremiumCurrency(premiumLargeAmount);
        }

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason) { }
}